class Solution:
    def findWords(self, board, words):
        trie = {}
        for word in words:
            node = trie
            for ch in word:
                node = node.setdefault(ch, {})
            node['$'] = word
        rows, cols = len(board), len(board[0])
        found = set()
        def dfs(r, c, node):
            if r < 0 or c < 0 or r == rows or c == cols:
                return
            ch = board[r][c]
            if ch == '#' or ch not in node:
                return
            nxt = node[ch]
            if '$' in nxt:
                found.add(nxt['$'])
            board[r][c] = '#'
            dfs(r + 1, c, nxt)
            dfs(r - 1, c, nxt)
            dfs(r, c + 1, nxt)
            dfs(r, c - 1, nxt)
            board[r][c] = ch
        for r in range(rows):
            for c in range(cols):
                dfs(r, c, trie)
        return sorted(found)
